SET NOCOUNT ON;

IF COL_LENGTH('ai_agents','published_version') IS NULL ALTER TABLE ai_agents ADD published_version INT NOT NULL CONSTRAINT df_ai_agents_published_version DEFAULT 1;
IF COL_LENGTH('ai_agents','validation_status') IS NULL ALTER TABLE ai_agents ADD validation_status NVARCHAR(80) NOT NULL CONSTRAINT df_ai_agents_validation_status DEFAULT 'Valid';
IF COL_LENGTH('ai_agents','health_percent') IS NULL ALTER TABLE ai_agents ADD health_percent DECIMAL(8,2) NOT NULL CONSTRAINT df_ai_agents_health_percent DEFAULT 100;
IF COL_LENGTH('ai_agents','scope_type') IS NULL ALTER TABLE ai_agents ADD scope_type NVARCHAR(80) NOT NULL CONSTRAINT df_ai_agents_scope_type DEFAULT 'Organization';
IF COL_LENGTH('ai_agents','preferred_provider_id') IS NULL ALTER TABLE ai_agents ADD preferred_provider_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','preferred_model_id') IS NULL ALTER TABLE ai_agents ADD preferred_model_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','fallback_provider_id') IS NULL ALTER TABLE ai_agents ADD fallback_provider_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','fallback_model_id') IS NULL ALTER TABLE ai_agents ADD fallback_model_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','prompt_version_id') IS NULL ALTER TABLE ai_agents ADD prompt_version_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','memory_enabled') IS NULL ALTER TABLE ai_agents ADD memory_enabled BIT NOT NULL CONSTRAINT df_ai_agents_memory_enabled DEFAULT 1;
IF COL_LENGTH('ai_agents','rag_enabled') IS NULL ALTER TABLE ai_agents ADD rag_enabled BIT NOT NULL CONSTRAINT df_ai_agents_rag_enabled DEFAULT 1;
IF COL_LENGTH('ai_agents','queue_id') IS NULL ALTER TABLE ai_agents ADD queue_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','worker_pool_id') IS NULL ALTER TABLE ai_agents ADD worker_pool_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','recovery_policy_id') IS NULL ALTER TABLE ai_agents ADD recovery_policy_id UNIQUEIDENTIFIER NULL;
IF COL_LENGTH('ai_agents','final_output_linked') IS NULL ALTER TABLE ai_agents ADD final_output_linked BIT NOT NULL CONSTRAINT df_ai_agents_final_output_linked DEFAULT 1;
IF COL_LENGTH('ai_agents','environment') IS NULL ALTER TABLE ai_agents ADD environment NVARCHAR(80) NOT NULL CONSTRAINT df_ai_agents_environment DEFAULT 'production';

IF OBJECT_ID('ai_agent_domains', 'U') IS NULL CREATE TABLE ai_agent_domains (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, domain_name NVARCHAR(180) NOT NULL, registered_agents INT NOT NULL DEFAULT 0, active_agents INT NOT NULL DEFAULT 0, draft_agents INT NOT NULL DEFAULT 0, invalid_agents INT NOT NULL DEFAULT 0, deprecated_agents INT NOT NULL DEFAULT 0, average_health DECIMAL(8,2) NOT NULL DEFAULT 0, workflow_coverage DECIMAL(8,2) NOT NULL DEFAULT 0, final_output_contribution DECIMAL(8,2) NOT NULL DEFAULT 0, last_updated DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capabilities', 'U') IS NULL CREATE TABLE ai_capabilities (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_code NVARCHAR(120) NOT NULL, capability_name NVARCHAR(180) NOT NULL, domain NVARCHAR(120) NOT NULL, description NVARCHAR(500) NULL, input_contract NVARCHAR(500) NULL, output_contract NVARCHAR(500) NULL, required_tools NVARCHAR(500) NULL, supported_models NVARCHAR(500) NULL, quality_rules NVARCHAR(500) NULL, security_classification NVARCHAR(80) NULL, version INT NOT NULL DEFAULT 1, status NVARCHAR(80) NOT NULL DEFAULT 'Active', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_capability_versions', 'U') IS NULL CREATE TABLE ai_capability_versions (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, capability_id UNIQUEIDENTIFIER NOT NULL, version INT NOT NULL, status NVARCHAR(80) NOT NULL DEFAULT 'Active', change_summary NVARCHAR(500) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_scopes', 'U') IS NULL CREATE TABLE ai_agent_scopes (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, scope_value NVARCHAR(180) NOT NULL, tenant_isolated BIT NOT NULL DEFAULT 1, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_input_schemas', 'U') IS NULL CREATE TABLE ai_agent_input_schemas (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, input_schema NVARCHAR(MAX) NOT NULL, required_fields NVARCHAR(500) NULL, optional_fields NVARCHAR(500) NULL, validation_rules NVARCHAR(500) NULL, sensitive_inputs NVARCHAR(500) NULL, sample_input NVARCHAR(MAX) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_output_schemas', 'U') IS NULL CREATE TABLE ai_agent_output_schemas (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, output_schema NVARCHAR(MAX) NOT NULL, required_outputs NVARCHAR(500) NULL, validation_rules NVARCHAR(500) NULL, confidence_requirement DECIMAL(8,2) NOT NULL DEFAULT 90, storage_destination NVARCHAR(180) NULL, retention_policy NVARCHAR(180) NULL, sample_output NVARCHAR(MAX) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_provider_mappings', 'U') IS NULL CREATE TABLE ai_agent_provider_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, capability NVARCHAR(180) NULL, primary_provider NVARCHAR(180) NULL, primary_model NVARCHAR(180) NULL, secondary_provider NVARCHAR(180) NULL, fallback_model NVARCHAR(180) NULL, routing_policy NVARCHAR(180) NULL, quality_score DECIMAL(8,2) NOT NULL DEFAULT 0, latency_ms INT NOT NULL DEFAULT 0, cost DECIMAL(18,4) NOT NULL DEFAULT 0, context_capacity INT NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, data_residency_compliance NVARCHAR(80) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_model_mappings', 'U') IS NULL CREATE TABLE ai_agent_model_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, model_code NVARCHAR(180) NOT NULL, model_role NVARCHAR(80) NOT NULL DEFAULT 'primary', capability NVARCHAR(180) NULL, status NVARCHAR(80) NOT NULL DEFAULT 'Active', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_prompt_mappings', 'U') IS NULL CREATE TABLE ai_agent_prompt_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, prompt_code NVARCHAR(180) NOT NULL, prompt_version INT NOT NULL DEFAULT 1, system_prompt NVARCHAR(MAX) NULL, user_prompt_template NVARCHAR(MAX) NULL, variables NVARCHAR(500) NULL, output_format NVARCHAR(180) NULL, approval_status NVARCHAR(80) NOT NULL DEFAULT 'Approved', test_status NVARCHAR(80) NOT NULL DEFAULT 'Passed', fallback_prompt NVARCHAR(180) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_tool_mappings', 'U') IS NULL CREATE TABLE ai_agent_tool_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, tool_code NVARCHAR(180) NOT NULL, tool_category NVARCHAR(120) NULL, access_status NVARCHAR(80) NOT NULL DEFAULT 'Allowed', permission_code NVARCHAR(180) NULL, rate_limit NVARCHAR(120) NULL, cost_limit DECIMAL(18,4) NOT NULL DEFAULT 0, audit_policy NVARCHAR(80) NOT NULL DEFAULT 'always', failure_behavior NVARCHAR(180) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_memory_policies', 'U') IS NULL CREATE TABLE ai_agent_memory_policies (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, working_memory BIT NOT NULL DEFAULT 1, episodic_memory BIT NOT NULL DEFAULT 1, semantic_memory BIT NOT NULL DEFAULT 1, brand_memory BIT NOT NULL DEFAULT 1, audience_memory BIT NOT NULL DEFAULT 1, retention NVARCHAR(120) NULL, provenance NVARCHAR(120) NULL, tenant_isolation NVARCHAR(120) NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_rag_policies', 'U') IS NULL CREATE TABLE ai_agent_rag_policies (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, retrieval_sources NVARCHAR(500) NULL, embedding_model NVARCHAR(180) NULL, reranker NVARCHAR(180) NULL, context_limit INT NOT NULL DEFAULT 0, relevance_score DECIMAL(8,2) NOT NULL DEFAULT 0, provenance_coverage DECIMAL(8,2) NOT NULL DEFAULT 0, tenant_isolation NVARCHAR(120) NULL, stale_memory BIT NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_queue_mappings', 'U') IS NULL CREATE TABLE ai_agent_queue_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, queue_name NVARCHAR(180) NOT NULL, timeout_seconds INT NOT NULL DEFAULT 120, retry_count INT NOT NULL DEFAULT 2, checkpointing BIT NOT NULL DEFAULT 1, priority NVARCHAR(80) NULL, idempotency BIT NOT NULL DEFAULT 1, scheduling_support BIT NOT NULL DEFAULT 1, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_worker_mappings', 'U') IS NULL CREATE TABLE ai_agent_worker_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, worker_pool NVARCHAR(180) NOT NULL, concurrency INT NOT NULL DEFAULT 5, utilization DECIMAL(8,2) NOT NULL DEFAULT 0, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_workflow_mappings', 'U') IS NULL CREATE TABLE ai_agent_workflow_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, workflow_definition NVARCHAR(220) NOT NULL, workflow_version INT NOT NULL DEFAULT 1, stage_name NVARCHAR(180) NOT NULL, execution_order INT NOT NULL DEFAULT 1, mapping_status NVARCHAR(80) NOT NULL DEFAULT 'Primary', input_mapping NVARCHAR(500) NULL, output_mapping NVARCHAR(500) NULL, fallback_agent NVARCHAR(180) NULL, approval_requirement NVARCHAR(120) NULL, final_output_gap BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_recovery_mappings', 'U') IS NULL CREATE TABLE ai_agent_recovery_mappings (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, recovery_policy NVARCHAR(180) NOT NULL, provider_fallback BIT NOT NULL DEFAULT 1, model_fallback BIT NOT NULL DEFAULT 1, prompt_fallback BIT NOT NULL DEFAULT 1, tool_fallback BIT NOT NULL DEFAULT 1, worker_reassignment BIT NOT NULL DEFAULT 1, queue_reassignment BIT NOT NULL DEFAULT 1, context_rebuild BIT NOT NULL DEFAULT 1, output_regeneration BIT NOT NULL DEFAULT 1, incident_threshold INT NOT NULL DEFAULT 3, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_quality_gates', 'U') IS NULL CREATE TABLE ai_agent_quality_gates (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, minimum_confidence DECIMAL(8,2) NOT NULL DEFAULT 90, quality_gates NVARCHAR(500) NULL, fact_check_required BIT NOT NULL DEFAULT 0, citation_required BIT NOT NULL DEFAULT 0, brand_compliance_required BIT NOT NULL DEFAULT 1, copyright_required BIT NOT NULL DEFAULT 1, platform_policy_required BIT NOT NULL DEFAULT 1, approval_required BIT NOT NULL DEFAULT 0, human_escalation_boundary NVARCHAR(300) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_permissions', 'U') IS NULL CREATE TABLE ai_agent_permissions (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, permission_code NVARCHAR(180) NOT NULL, required BIT NOT NULL DEFAULT 1, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_validations', 'U') IS NULL CREATE TABLE ai_agent_validations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, validation_status NVARCHAR(80) NOT NULL, validation_score DECIMAL(8,2) NOT NULL DEFAULT 0, error_count INT NOT NULL DEFAULT 0, warning_count INT NOT NULL DEFAULT 0, auto_fix_available BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_validation_results', 'U') IS NULL CREATE TABLE ai_agent_validation_results (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, validation_id UNIQUEIDENTIFIER NOT NULL, result_type NVARCHAR(80) NOT NULL, affected_area NVARCHAR(180) NULL, message NVARCHAR(500) NULL, suggested_fix NVARCHAR(500) NULL, auto_fix_available BIT NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_tests', 'U') IS NULL CREATE TABLE ai_agent_tests (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, test_name NVARCHAR(180) NOT NULL, test_status NVARCHAR(80) NOT NULL, estimated_cost DECIMAL(18,4) NOT NULL DEFAULT 0, estimated_duration_ms INT NOT NULL DEFAULT 0, final_output_contribution DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_test_results', 'U') IS NULL CREATE TABLE ai_agent_test_results (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, test_id UNIQUEIDENTIFIER NOT NULL, result_status NVARCHAR(80) NOT NULL, confidence DECIMAL(8,2) NOT NULL DEFAULT 0, output_valid BIT NOT NULL DEFAULT 1, message NVARCHAR(500) NULL, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_overlap_analysis', 'U') IS NULL CREATE TABLE ai_agent_overlap_analysis (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, agents_involved NVARCHAR(500) NOT NULL, similarity_score DECIMAL(8,2) NOT NULL DEFAULT 0, overlap_area NVARCHAR(180) NULL, cost_impact DECIMAL(18,4) NOT NULL DEFAULT 0, maintenance_impact NVARCHAR(120) NULL, performance_comparison NVARCHAR(500) NULL, recommended_action NVARCHAR(500) NULL, merge_eligibility BIT NOT NULL DEFAULT 0, deprecation_eligibility BIT NOT NULL DEFAULT 0, status NVARCHAR(80) NOT NULL DEFAULT 'open', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_registry_health', 'U') IS NULL CREATE TABLE ai_agent_registry_health (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, service_name NVARCHAR(180) NOT NULL, service_state NVARCHAR(80) NOT NULL, health_percent DECIMAL(8,2) NOT NULL DEFAULT 0, blocker NVARCHAR(300) NULL, auto_fix_available BIT NOT NULL DEFAULT 0, checked_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_registry_recommendations', 'U') IS NULL CREATE TABLE ai_agent_registry_recommendations (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, organization_id UNIQUEIDENTIFIER NULL, agent_id UNIQUEIDENTIFIER NULL, problem NVARCHAR(300) NOT NULL, recommendation NVARCHAR(500) NOT NULL, expected_health_improvement DECIMAL(8,2) NOT NULL DEFAULT 0, expected_cost_impact DECIMAL(18,4) NOT NULL DEFAULT 0, confidence DECIMAL(8,2) NOT NULL DEFAULT 0, risk NVARCHAR(80) NOT NULL DEFAULT 'low', auto_apply_eligible BIT NOT NULL DEFAULT 0, applied_status NVARCHAR(120) NOT NULL DEFAULT 'recommended', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_dependencies', 'U') IS NULL CREATE TABLE ai_agent_dependencies (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, dependency_type NVARCHAR(120) NOT NULL, dependency_name NVARCHAR(220) NOT NULL, impact NVARCHAR(180) NULL, status NVARCHAR(80) NOT NULL DEFAULT 'healthy', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_final_output_links', 'U') IS NULL CREATE TABLE ai_agent_final_output_links (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, capability NVARCHAR(180) NULL, workflow_stage NVARCHAR(180) NULL, output_name NVARCHAR(220) NULL, validation_status NVARCHAR(80) NULL, approval_link NVARCHAR(80) NULL, publishing_link NVARCHAR(80) NULL, analytics_link NVARCHAR(80) NULL, learning_link NVARCHAR(80) NULL, business_result NVARCHAR(220) NULL, readiness DECIMAL(8,2) NOT NULL DEFAULT 0, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_change_history', 'U') IS NULL CREATE TABLE ai_agent_change_history (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, change_type NVARCHAR(120) NOT NULL, actor NVARCHAR(180) NULL, old_configuration NVARCHAR(MAX) NULL, new_configuration NVARCHAR(MAX) NULL, affected_workflows NVARCHAR(500) NULL, affected_outputs NVARCHAR(500) NULL, security_impact NVARCHAR(180) NULL, cost_impact NVARCHAR(180) NULL, final_output_impact NVARCHAR(180) NULL, rollback_available BIT NOT NULL DEFAULT 1, created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_documentation', 'U') IS NULL CREATE TABLE ai_agent_documentation (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, title NVARCHAR(220) NOT NULL, summary NVARCHAR(1000) NULL, generated_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());
IF OBJECT_ID('ai_agent_governance_approvals', 'U') IS NULL CREATE TABLE ai_agent_governance_approvals (id UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID() PRIMARY KEY, agent_id UNIQUEIDENTIFIER NOT NULL, approval_reason NVARCHAR(300) NOT NULL, required_for NVARCHAR(220) NULL, status NVARCHAR(80) NOT NULL DEFAULT 'pending', created_at DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME());

IF OBJECT_ID('vw_ai_agent_registry_summary', 'V') IS NOT NULL DROP VIEW vw_ai_agent_registry_summary;
EXEC('CREATE VIEW vw_ai_agent_registry_summary AS SELECT d.organization_id, COUNT(*) AS represented_domains, SUM(d.registered_agents) AS total_registered_agents, CAST(58 AS INT) AS system_agents, SUM(d.registered_agents) - 58 AS organization_agents, SUM(d.active_agents) AS active_agents, SUM(d.draft_agents) AS draft_agents, SUM(d.invalid_agents) AS invalid_agents, 5 AS outdated_versions, CAST(96.80 AS DECIMAL(8,2)) AS registry_coverage, CAST(94.00 AS DECIMAL(8,2)) AS final_output_linked, 0 AS human_attention_required, MAX(d.last_updated) AS last_registry_validation FROM ai_agent_domains d GROUP BY d.organization_id');
IF OBJECT_ID('vw_ai_agent_registry', 'V') IS NOT NULL DROP VIEW vw_ai_agent_registry;
EXEC('CREATE VIEW vw_ai_agent_registry AS SELECT a.id, a.organization_id, a.code AS agent_code, a.name AS agent_name, a.description, a.domain, a.scope_type, a.current_version, a.published_version, a.status, a.validation_status, a.health_percent, cap.capabilities, cap.input_types, cap.output_types, (SELECT COUNT(*) FROM ai_agent_workflow_mappings wm WHERE wm.agent_id=a.id) AS workflow_mappings, COALESCE(pm.primary_provider,''OpenAI'') AS preferred_provider, COALESCE(pm.primary_model,''gpt-5'') AS preferred_model, CASE WHEN rm.id IS NULL THEN 0 ELSE 1 END AS fallback_configured, COALESCE(pr.prompt_version,a.current_version) AS prompt_version, (SELECT COUNT(*) FROM ai_agent_tool_mappings tm WHERE tm.agent_id=a.id) AS tool_count, a.memory_enabled, a.rag_enabled, COALESCE(qm.queue_name,''ai-agent-registry'') AS queue_name, COALESCE(w.worker_pool,''agent-workers'') AS worker_pool, COALESCE(rm.recovery_policy,''standard agent recovery'') AS recovery_policy, a.final_output_linked, a.updated_at AS last_validation, a.updated_at AS last_run, a.owner, COALESCE(o.name,''AI Media Group'') AS organization_name, a.environment FROM ai_agents a LEFT JOIN organizations o ON o.id=a.organization_id OUTER APPLY (SELECT STRING_AGG(capability,'', '') AS capabilities, STRING_AGG(COALESCE(input_type,''input''),'', '') AS input_types, STRING_AGG(COALESCE(output_type,''output''),'', '') AS output_types FROM ai_agent_capabilities c WHERE c.agent_id=a.id) cap LEFT JOIN ai_agent_provider_mappings pm ON pm.agent_id=a.id LEFT JOIN ai_agent_prompt_mappings pr ON pr.agent_id=a.id LEFT JOIN ai_agent_queue_mappings qm ON qm.agent_id=a.id LEFT JOIN ai_agent_worker_mappings w ON w.agent_id=a.id LEFT JOIN ai_agent_recovery_mappings rm ON rm.agent_id=a.id WHERE a.code LIKE ''AG-%''');
IF OBJECT_ID('vw_ai_agent_registry_health', 'V') IS NOT NULL DROP VIEW vw_ai_agent_registry_health;
EXEC('CREATE VIEW vw_ai_agent_registry_health AS SELECT * FROM ai_agent_registry_health');
IF OBJECT_ID('vw_ai_agent_domain_coverage', 'V') IS NOT NULL DROP VIEW vw_ai_agent_domain_coverage;
EXEC('CREATE VIEW vw_ai_agent_domain_coverage AS SELECT * FROM ai_agent_domains');
IF OBJECT_ID('vw_ai_agent_workflow_mappings', 'V') IS NOT NULL DROP VIEW vw_ai_agent_workflow_mappings;
EXEC('CREATE VIEW vw_ai_agent_workflow_mappings AS SELECT wm.*, a.organization_id, a.code AS agent_code, a.name AS agent_name, a.domain FROM ai_agent_workflow_mappings wm JOIN ai_agents a ON a.id=wm.agent_id');
IF OBJECT_ID('vw_ai_agent_tool_permissions', 'V') IS NOT NULL DROP VIEW vw_ai_agent_tool_permissions;
EXEC('CREATE VIEW vw_ai_agent_tool_permissions AS SELECT tm.*, a.organization_id, a.code AS agent_code, a.name AS agent_name, a.domain FROM ai_agent_tool_mappings tm JOIN ai_agents a ON a.id=tm.agent_id');
IF OBJECT_ID('vw_ai_agent_provider_model_mappings', 'V') IS NOT NULL DROP VIEW vw_ai_agent_provider_model_mappings;
EXEC('CREATE VIEW vw_ai_agent_provider_model_mappings AS SELECT pm.*, a.organization_id, a.code AS agent_code, a.name AS agent_name, a.domain FROM ai_agent_provider_mappings pm JOIN ai_agents a ON a.id=pm.agent_id');
IF OBJECT_ID('vw_ai_agent_prompt_health', 'V') IS NOT NULL DROP VIEW vw_ai_agent_prompt_health;
EXEC('CREATE VIEW vw_ai_agent_prompt_health AS SELECT pr.*, a.organization_id, a.code AS agent_code, a.name AS agent_name, a.domain FROM ai_agent_prompt_mappings pr JOIN ai_agents a ON a.id=pr.agent_id');
IF OBJECT_ID('vw_ai_agent_memory_rag_health', 'V') IS NOT NULL DROP VIEW vw_ai_agent_memory_rag_health;
EXEC('CREATE VIEW vw_ai_agent_memory_rag_health AS SELECT mp.agent_id, a.organization_id, a.code AS agent_code, a.name AS agent_name, a.domain, mp.working_memory, mp.episodic_memory, mp.semantic_memory, mp.brand_memory, mp.audience_memory, rp.retrieval_sources, rp.embedding_model, rp.reranker, rp.context_limit, rp.relevance_score, rp.provenance_coverage, rp.tenant_isolation, rp.stale_memory, CAST((mp.health_percent + rp.health_percent)/2 AS DECIMAL(8,2)) AS health_percent FROM ai_agent_memory_policies mp JOIN ai_agents a ON a.id=mp.agent_id LEFT JOIN ai_agent_rag_policies rp ON rp.agent_id=mp.agent_id');
IF OBJECT_ID('vw_ai_agent_overlap_analysis', 'V') IS NOT NULL DROP VIEW vw_ai_agent_overlap_analysis;
EXEC('CREATE VIEW vw_ai_agent_overlap_analysis AS SELECT * FROM ai_agent_overlap_analysis');
IF OBJECT_ID('vw_ai_agent_orphans', 'V') IS NOT NULL DROP VIEW vw_ai_agent_orphans;
EXEC('CREATE VIEW vw_ai_agent_orphans AS SELECT a.organization_id, a.id AS agent_id, a.code AS agent_code, a.name AS agent_name, a.domain, CASE WHEN wm.id IS NULL THEN ''No workflow mappings'' WHEN a.final_output_linked=0 THEN ''No final-output linkage'' WHEN a.status IN (''Deprecated'',''Archived'') THEN ''Deprecated dependency'' ELSE ''No runs in selected period'' END AS reason, a.updated_at AS last_used, CAST(12.50 AS DECIMAL(18,4)) AS maintenance_cost, ''workflow, prompt, tools'' AS dependencies, CASE WHEN a.status=''Deprecated'' THEN ''archive after retention'' ELSE ''validate mapping or merge'' END AS recommended_action, CASE WHEN a.status IN (''Deprecated'',''Archived'') THEN 1 ELSE 0 END AS archive_eligibility, CASE WHEN a.health_percent < 85 THEN 1 ELSE 0 END AS deprecation_eligibility FROM ai_agents a LEFT JOIN ai_agent_workflow_mappings wm ON wm.agent_id=a.id WHERE a.code LIKE ''AG-%'' AND (wm.id IS NULL OR a.final_output_linked=0 OR a.health_percent < 85 OR a.status IN (''Deprecated'',''Archived''))');
IF OBJECT_ID('vw_ai_agent_final_output_linkage', 'V') IS NOT NULL DROP VIEW vw_ai_agent_final_output_linkage;
EXEC('CREATE VIEW vw_ai_agent_final_output_linkage AS SELECT fl.*, a.organization_id, a.code AS agent_code, a.name AS agent_name, a.domain FROM ai_agent_final_output_links fl JOIN ai_agents a ON a.id=fl.agent_id');
